import numpy as np
from qiskit import QuantumCircuit
from qiskit.quantum_info import Operator

def op(build):
    qc = QuantumCircuit(1)
    build(qc)
    return Operator(qc)

pairs = {
    "A": ("X vs Y", op(lambda c: c.x(0)), op(lambda c: c.y(0))),
    "B": ("Z vs RZ(pi)", op(lambda c: c.z(0)), op(lambda c: c.rz(np.pi, 0))),
    "C": ("X vs RX(pi)", op(lambda c: c.x(0)), op(lambda c: c.rx(np.pi, 0))),
    "D": ("H vs Z", op(lambda c: c.h(0)), op(lambda c: c.z(0))),
}
evidence = {}
proven = []
for k, (name, a, b) in pairs.items():
    eq = bool(a.equiv(b))
    ident = bool(a == b)
    evidence[k] = f"{name}: Operator.equiv()={eq} (exact ==? {ident})"
    if eq:
        proven.append(k)
emit_verdict({"answer": sorted(proven), "evidence": evidence,
              "observed": {k: bool(a.equiv(b)) for k, (_, a, b) in pairs.items()}})
